// src/pages/member/GroupDetail.js
import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import Layout from '../../components/shared/Layout';
import { groupAPI, payoutAPI, urgencyAPI } from '../../services/api';
import toast from 'react-hot-toast';

export default function GroupDetail() {
  const { id } = useParams();
  const [group,   setGroup]   = useState(null);
  const [members, setMembers] = useState([]);
  const [payouts, setPayouts] = useState(null);
  const [urgency, setUrgency] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      groupAPI.getGroupById(id),
      groupAPI.getGroupMembers(id),
      payoutAPI.getHistory(id),
      urgencyAPI.getByGroup(id),
    ]).then(([g, m, p, u]) => {
      setGroup(g.data.data);
      setMembers(m.data.data || []);
      setPayouts(p.data.data);
      setUrgency(u.data.data || []);
    }).catch(() => toast.error('Could not load group details'))
    .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <Layout><div className="spinner-wrap"><div className="spinner"/></div></Layout>;
  if (!group)  return <Layout><div className="empty"><h3>Group not found</h3></div></Layout>;

  return (
    <Layout>
      <div className="flex-between" style={{ marginBottom: '1.5rem' }}>
        <div>
          <h2>{group.name}</h2>
          <p className="text-grey">{group.description}</p>
        </div>
        <div className="flex gap-1">
          <Link to={`/member/payments/${id}`}  className="btn btn-primary">Pay Now</Link>
          <Link to={`/member/payouts/${id}`}   className="btn btn-outline">Payout History</Link>
          <Link to={`/member/urgency/${id}`}   className="btn btn-outline">Urgency</Link>
        </div>
      </div>

      <div className="grid-4" style={{ marginBottom: '2rem' }}>
        <div className="stat-card"><div className="stat-label">Total Pot</div><div className="stat-value">₹{group.totalAmount?.toLocaleString()}</div></div>
        <div className="stat-card"><div className="stat-label">Your Contribution</div><div className="stat-value">₹{group.contributionPerMember?.toLocaleString()}</div></div>
        <div className="stat-card"><div className="stat-label">Members</div><div className="stat-value">{group.currentMemberCount}/{group.maxMembers}</div></div>
        <div className="stat-card"><div className="stat-label">Current Cycle</div><div className="stat-value">{group.currentCycleMonth}</div><div className="stat-sub">{group.payoutMethod?.replace(/_/g,' ')}</div></div>
      </div>

      <div className="grid-2">
        {/* Members list */}
        <div className="card">
          <h3 style={{ marginBottom: '1rem' }}>Members</h3>
          <div className="table-wrapper">
            <table>
              <thead><tr><th>Name</th><th>Status</th>{group.payoutMethod === 'FIXED_ROTATION' && <th>Order</th>}<th>Payout</th></tr></thead>
              <tbody>
                {members.map(m => (
                  <tr key={m.id}>
                    <td><strong>{m.name}</strong><br/><span className="text-grey text-sm">{m.phone}</span></td>
                    <td><span className={`badge badge-${m.status==='ACTIVE'?'success':m.status==='PENDING'?'warning':'grey'}`}>{m.status}</span></td>
                    {group.payoutMethod === 'FIXED_ROTATION' && <td>#{m.rotationOrder || '—'}</td>}
                    <td>{m.hasReceivedPayout ? <span className="badge badge-info">Cycle {m.payoutReceivedOnCycle}</span> : <span className="text-grey text-sm">Pending</span>}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Payout history */}
        <div className="card">
          <h3 style={{ marginBottom: '1rem' }}>Recent Payouts</h3>
          {payouts?.cycles?.length === 0 ? (
            <div className="empty"><p>No payouts yet</p></div>
          ) : (
            <div className="table-wrapper">
              <table>
                <thead><tr><th>Cycle</th><th>Winner</th><th>Amount</th></tr></thead>
                <tbody>
                  {payouts?.cycles?.slice(0,5).map(c => (
                    <tr key={c.id}>
                      <td>#{c.cycleNumber}</td>
                      <td>{c.winnerName || '—'}</td>
                      <td>₹{c.winnerAmount?.toLocaleString()}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
}
